%% MATLAB Equivalent
symbols = (randi([0 1], N, 1)*2-1 + 1j*(randi([0 1], N, 1)*2-1))/sqrt(2);
sig_power = mean(abs(symbols).^2);
noise_power = sig_power / (10^(snr_dB/10));
noise = sqrt(noise_power/2) * (randn(N,1) + 1j*randn(N,1));
received = symbols + noise;

